return items.map(item => {
  const json = item.json;

  const subject =
    json.subject ||
    json.Subject ||
    json.headers?.subject ||
    'Untitled newsletter';

  const from =
    json.from?.text ||
    json.from ||
    json.From ||
    json.headers?.from ||
    'Unknown sender';

  const senderEmail = (
    json.from?.value?.[0]?.address ||
    (typeof json.from === 'string' ? json.from.match(/[\w.-]+@[\w.-]+/)?.[0] : null) ||
    'unknown'
  ).toLowerCase();

  const senderSlug = senderEmail
    .replace(/@.*$/, '')
    .replace(/[^a-z0-9]+/g, '-')
    .slice(0, 40);

  const date =
    json.date ||
    json.Date ||
    json.internalDate ||
    new Date().toISOString();

  const html =
    json.html ||
    json.textHtml ||
    json.body?.html ||
    json.payload?.body?.data ||
    '';

  const text =
    json.text ||
    json.textPlain ||
    json.body?.text ||
    '';

  const sourceMessageId =
    json.id ||
    json.messageId ||
    json.message_id ||
    `${senderEmail}-${subject}-${date}`;

  return {
    json: {
      subject,
      from,
      senderEmail,
      senderSlug,
      date,
      html,
      text,
      sourceMessageId,
    },
  };
});

function extractLinksFromHtml(html) {
  const links = [];
  const regex = /<a\s+(?:[^>]*?\s+)?href=(["'])(.*?)\1[^>]*>([\s\S]*?)<\/a>/gi;
  let match;
  while ((match = regex.exec(html)) !== null) {
    const href = match[2];
    const anchorText = match[3].replace(/<[^>]+>/g, '').trim();
    links.push({ href, anchorText });
  }
  return links;
}

function extractLinksFromText(text) {
  const regex = /(https?:\/\/[^\s<>"')\]]+)/gi;
  const matches = text.match(regex) || [];
  return matches.map(href => ({ href, anchorText: '' }));
}

const output = [];

for (const item of items) {
  const { subject, from, senderEmail, senderSlug, date, html, text, sourceMessageId } = item.json;

  let links = [];
  if (html) {
    links = extractLinksFromHtml(html);
  }
  if (links.length === 0 && text) {
    links = extractLinksFromText(text);
  }

  for (const { href, anchorText } of links) {
    output.push({
      json: {
        rawUrl: href,
        anchorText,
        newsletterSubject: subject,
        newsletterFrom: from,
        senderEmail,
        senderSlug,
        newsletterDate: date,
        sourceMessageId,
      },
    });
  }
}

return output;

const TRACKING_PARAMS = new Set([
  'utm_source', 'utm_medium', 'utm_campaign', 'utm_term',
  'utm_content', 'utm_id', 'mc_cid', 'mc_eid', 'igshid',
  'fbclid', 'gclid', 'msclkid', 'vero_id', '_hsenc', '_hsmi',
  'ck_subscriber_id', 'ref', 'source',
]);

const REDIRECT_HOSTS = [
  'mailchi.mp', 'list-manage.com', 'sendgrid.net',
  'substack.com', 'buttondown.email', 'convertkit-mail.com',
  'beehiiv.com', 'click.convertkit-mail.com',
  'email.mg', 'links.', 'click.', 'trk.',
  'customer.io', 'hubspot.com', 'hs-analytics.net',
];

const REDIRECT_PARAMS = [
  'url', 'u', 'target', 'redirect', 'redirect_url',
  'destination', 'link', 'goto',
];

function isRedirectHost(hostname) {
  const host = hostname.toLowerCase();
  return REDIRECT_HOSTS.some(pattern =>
    host === pattern ||
    host.endsWith('.' + pattern) ||
    host.includes(pattern)
  );
}

function unwrapRedirect(url, depth = 0) {
  if (depth > 3) return url;
  let parsed;
  try { parsed = new URL(url); } catch { return url; }
  if (!isRedirectHost(parsed.hostname)) return url;
  for (const param of REDIRECT_PARAMS) {
    const value = parsed.searchParams.get(param);
    if (value && value.startsWith('http')) {
      return unwrapRedirect(value, depth + 1);
    }
  }
  const pathMatch = parsed.pathname.match(/\/(https?:\/\/.+)/);
  if (pathMatch) {
    return unwrapRedirect(decodeURIComponent(pathMatch[1]), depth + 1);
  }
  return url;
}

function cleanUrl(rawUrl) {
  let url = rawUrl.replace(/&amp;/g, '&').trim();
  url = unwrapRedirect(url);
  let parsed;
  try { parsed = new URL(url); } catch { return null; }
  if (!['http:', 'https:'].includes(parsed.protocol)) return null;
  for (const param of [...parsed.searchParams.keys()]) {
    if (TRACKING_PARAMS.has(param.toLowerCase())) {
      parsed.searchParams.delete(param);
    }
  }
  parsed.hash = '';
  return parsed.toString();
}

return items
  .map(item => {
    const clean = cleanUrl(item.json.rawUrl);
    if (!clean) return null;
    return { json: { ...item.json, url: clean } };
  })
  .filter(Boolean);

const BLOCKED_HOSTS = new Set([
  'twitter.com', 'x.com', 'facebook.com', 'instagram.com',
  'linkedin.com', 'youtube.com', 'tiktok.com', 'threads.net',
]);

const BLOCKED_HOST_PATTERNS = [
  'mailchi.mp', 'list-manage.com', 'beehiiv.com',
  'buttondown.email', 'convertkit',
  'sendgrid.net', 'customer.io',
];

const BLOCKED_PATH_KEYWORDS = [
  'unsubscribe', 'preferences', 'manage-subscription',
  'email-preferences', 'view-in-browser', 'web-version',
  'privacy', 'terms', 'forward-to-friend',
  'archive', 'profile', 'account', 'settings',
  'share', 'referral',
];

const IMAGE_EXTENSIONS = /\.(png|jpg|jpeg|gif|webp|svg|ico|bmp)(\?|$)/i;

function shouldKeep(url, anchorText) {
  let parsed;
  try { parsed = new URL(url); } catch { return false; }

  const host = parsed.hostname.replace(/^www\./, '').toLowerCase();
  const path = parsed.pathname.toLowerCase();
  const anchor = (anchorText || '').toLowerCase();

  if (BLOCKED_HOSTS.has(host)) return false;
  if (BLOCKED_HOST_PATTERNS.some(p => host.includes(p))) return false;
  if (BLOCKED_PATH_KEYWORDS.some(kw => path.includes(kw) || anchor.includes(kw))) return false;
  if (IMAGE_EXTENSIONS.test(url)) return false;
  if (parsed.pathname === '/' || parsed.pathname === '') return false;

  return true;
}

return items.filter(item => shouldKeep(item.json.url, item.json.anchorText));

const seen = new Set();
const output = [];

for (const item of items) {
  const key = item.json.url;
  if (seen.has(key)) continue;
  seen.add(key);
  output.push(item);
}

return output;

const results = [];

for (const item of items) {
  const url = item.json.url;
  let title = item.json.anchorText || '';

  if (title.length < 10) {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 5000);

      const response = await fetch(url, {
        signal: controller.signal,
        headers: {
          'User-Agent': 'Mozilla/5.0 (compatible; FeedBot/1.0)',
          'Accept': 'text/html',
        },
        redirect: 'follow',
      });
      clearTimeout(timeout);

      if (response.ok) {
        const text = await response.text();
        const html = text.slice(0, 50000);
        const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
        if (titleMatch) {
          title = titleMatch[1]
            .replace(/\s+/g, ' ')
            .replace(/&amp;/g, '&')
            .replace(/&lt;/g, '<')
            .replace(/&gt;/g, '>')
            .replace(/&#x27;/g, "'")
            .replace(/&quot;/g, '"')
            .trim();
        }
      }
    } catch (e) {
      // Timeout or network error — use fallback
    }
  }

  if (!title || title.length < 3) {
    try {
      const parsed = new URL(url);
      title = decodeURIComponent(parsed.hostname.replace(/^www\./, '') + parsed.pathname)
        .replace(/[\/-]/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    } catch {
      title = url;
    }
  }

  results.push({
    json: {
      ...item.json,
      title,
    },
  });
}

return results;

const fs = require('fs');
const feedToken = process.env.FEED_TOKEN;
const statePath = `/feeds/${feedToken}/state.json`;

let existingItems = [];
if (fs.existsSync(statePath)) {
  try {
    existingItems = JSON.parse(fs.readFileSync(statePath, 'utf8'));
  } catch {
    existingItems = [];
  }
}

return [{
  json: {
    existingItems,
    newItems: items.map(item => item.json),
    feedToken,
  },
}];

const crypto = require('crypto');

function guidForUrl(url) {
  return crypto.createHash('sha256').update(url).digest('hex').slice(0, 32);
}

const { existingItems, newItems, feedToken } = items[0].json;

const byGuid = new Map();

for (const item of existingItems) {
  byGuid.set(item.guid, item);
}

let addedCount = 0;
for (const item of newItems) {
  const guid = guidForUrl(item.url);
  if (byGuid.has(guid)) continue;

  byGuid.set(guid, {
    guid,
    title: item.title || item.anchorText || item.url,
    link: item.url,
    pubDate: new Date(item.newsletterDate || Date.now()).toUTCString(),
    sourceNewsletter: item.newsletterSubject,
    sourceFrom: item.newsletterFrom,
    senderSlug: item.senderSlug,
    senderEmail: item.senderEmail,
    addedAt: new Date().toISOString(),
  });
  addedCount++;
}

const merged = [...byGuid.values()]
  .sort((a, b) => new Date(b.addedAt) - new Date(a.addedAt))
  .slice(0, 500);

return [{
  json: {
    items: merged,
    feedToken,
    addedCount,
    totalCount: merged.length,
  },
}];

const fs = require('fs');
const path = require('path');

function escapeXml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

function generateRss(feedTitle, feedDescription, feedLink, feedItems) {
  const rssItems = feedItems.map(item => `  <item>
    <title>${escapeXml(item.title)}</title>
    <link>${escapeXml(item.link)}</link>
    <guid isPermaLink="false">${escapeXml(item.guid)}</guid>
    <pubDate>${item.pubDate}</pubDate>
    <description>${escapeXml(`From: ${item.sourceNewsletter || 'newsletter'} (${item.sourceFrom || ''})`)}</description>
    <source url="${escapeXml(feedLink)}">${escapeXml(item.sourceNewsletter || 'Newsletter')}</source>
  </item>`).join('\n');

  return `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">
<channel>
  <title>${escapeXml(feedTitle)}</title>
  <link>${escapeXml(feedLink)}</link>
  <description>${escapeXml(feedDescription)}</description>
  <language>en</language>
  <lastBuildDate>${new Date().toUTCString()}</lastBuildDate>
  <atom:link href="${escapeXml(feedLink)}" rel="self" type="application/rss+xml"/>
${rssItems}
</channel>
</rss>`;
}

const { items: feedItems, feedToken, addedCount, totalCount } = items[0].json;
const feedsDir = `/feeds/${feedToken}`;
const baseUrl = `https://feeds.noamelf.com/${feedToken}`;

fs.mkdirSync(feedsDir, { recursive: true });

// Combined feed
const allXml = generateRss(
  'Newsletter Links',
  'All links extracted from newsletters',
  `${baseUrl}/all.xml`,
  feedItems
);
fs.writeFileSync(path.join(feedsDir, 'all.xml'), allXml, 'utf8');

// Per-newsletter feeds
const bySlug = {};
for (const item of feedItems) {
  const slug = item.senderSlug || 'unknown';
  if (!bySlug[slug]) bySlug[slug] = [];
  bySlug[slug].push(item);
}

const feedFiles = ['all.xml'];
for (const [slug, slugItems] of Object.entries(bySlug)) {
  const filename = `${slug}.xml`;
  const xml = generateRss(
    `Newsletter Links: ${slugItems[0]?.sourceFrom || slug}`,
    `Links from ${slug}`,
    `${baseUrl}/${filename}`,
    slugItems
  );
  fs.writeFileSync(path.join(feedsDir, filename), xml, 'utf8');
  feedFiles.push(filename);
}

// Write state
fs.writeFileSync(
  path.join(feedsDir, 'state.json'),
  JSON.stringify(feedItems, null, 2),
  'utf8'
);

return [{
  json: {
    status: 'ok',
    addedCount,
    totalCount,
    feedFiles,
    combinedFeedUrl: `${baseUrl}/all.xml`,
    perNewsletterFeeds: Object.keys(bySlug).map(slug => `${baseUrl}/${slug}.xml`),
  },
}];
